// Office review: convert a Pending slip into a draft PI/SI (THE RULE: one slip = one doc).
// Multi-item: rates are filled per goods row in the grid before converting.
frappe.ui.form.on("Driver Slip", {
	refresh(frm) {
		if (frm.is_new() || frm.doc.status !== "Pending Review") return;

		frm.add_custom_button(__("Make Invoice"), () => {
			const missing = (frm.doc.items || []).filter((r) => !(r.rate_inc > 0));
			if (missing.length) {
				frappe.msgprint(__("Fill Rate ₹/bag on every goods row first — missing on: {0}", [missing.map((r) => r.item).join(", ")]));
				return;
			}
			if (frm.is_dirty()) {
				frappe.msgprint(__("Save the slip first (unsaved rate edits)."));
				return;
			}
			const leg = frm.doc.direction === "Purchase" ? __("Purchase Invoice (from KP)") : __("Sales Invoice (to KP)");
			frappe.confirm(
				__("Create draft {0}?", [leg]) + "<br><b>" + frappe.utils.escape_html(frm.doc.items_summary || "") + "</b><br>" + __("Warehouse: {0}", [frappe.utils.escape_html(frm.doc.warehouse || "")]),
				() => {
					frappe.call({
						method: "driver_slip_make_invoice",
						args: { slip: frm.doc.name },
						freeze: true,
						freeze_message: __("Creating draft invoice…"),
						callback: (r) => {
							if (!r.message) return;
							frappe.show_alert({ message: __("Draft {0} created", [r.message.invoice]), indicator: "green" });
							frm.reload_doc();
						},
					});
				}
			);
		}).addClass("btn-primary");

		// duplicate-eyes-on: same challan + date already captured elsewhere?
		if (frm.doc.challan_no) {
			frappe.db.get_list("Driver Slip", {
				filters: { challan_no: frm.doc.challan_no, slip_date: frm.doc.slip_date, name: ["!=", frm.doc.name] },
				fields: ["name", "status"],
				limit: 5,
			}).then((rows) => {
				if (rows && rows.length) {
					frm.dashboard.add_comment(
						__("⚠️ Same challan no + date also on: {0}", [rows.map((r) => r.name).join(", ")]),
						"orange",
						true
					);
				}
			});
		}
	},
});

