// Stock Count Session — office review form.
// One button: turn the counted lines into a DRAFT Stock Reconciliation.
// Zero-variance lines stay here as the record that the item WAS counted;
// only real differences reach the reconciliation.
frappe.ui.form.on("Stock Count Session", {
    refresh: function (frm) {
        if (frm.is_new()) { return; }

        if (frm.doc.recon_ref) {
            frm.add_custom_button(__("Open Stock Reconciliation"), function () {
                frappe.set_route("Form", "Stock Reconciliation", frm.doc.recon_ref);
            });
        }

        if (frm.doc.status !== "Reconciled" && frm.doc.status !== "Rejected") {
            frm.add_custom_button(__("Make Stock Reconciliation"), function () {
                var n = frm.doc.lines_variance || 0;
                var msg = n
                    ? __("Create a draft Stock Reconciliation with {0} differing item(s)? It will post at the count time ({1} {2}), not now.",
                         [n, frm.doc.count_date, frm.doc.count_time || ""])
                    : __("Every counted line matched the book. Mark this session Reconciled without creating a Stock Reconciliation?");
                frappe.confirm(msg, function () {
                    frappe.call({
                        method: "stock_count_make_recon",
                        args: { session: frm.doc.name },
                        freeze: true,
                        freeze_message: __("Building reconciliation..."),
                        callback: function (r) {
                            var m = r.message || {};
                            if (m.recon) {
                                frappe.show_alert({ message: __("Draft {0} created", [m.recon]), indicator: "green" });
                                frappe.set_route("Form", "Stock Reconciliation", m.recon);
                            } else {
                                frappe.msgprint(m.note || __("Nothing to reconcile"));
                                frm.reload_doc();
                            }
                        }
                    });
                });
            }).addClass("btn-primary");
        }

        if (frm.doc.lines_counted) {
            var matched = (frm.doc.lines_counted || 0) - (frm.doc.lines_variance || 0);
            frm.dashboard.add_indicator(
                __("{0} counted · {1} matched · {2} differ", [frm.doc.lines_counted, matched, frm.doc.lines_variance || 0]),
                (frm.doc.lines_variance ? "orange" : "green")
            );
        }
    }
});
